import React, { useState, useEffect, useRef, Suspense } from "react";
import { Canvas } from "@react-three/fiber";
import { 
  OrbitControls, 
  useGLTF, 
  Environment, 
  PresentationControls,
  Stage,
  ContactShadows
} from "@react-three/drei";
import { useParams, useNavigate } from 'react-router-dom';
import * as THREE from 'three';
import { GLTFLoader } from 'three/addons/loaders/GLTFLoader.js';
import axios from 'axios';

function Model({ url }) {
  const { scene } = useGLTF(url);
  return <primitive object={scene} scale={0.5} position={[0, -1, 0]} />;
}

// Preload the model
useGLTF.preload("http://localhost:3000/public/uploads/mustang.glb");

const PalmTree = ({ position, scale = 1 }) => {
  return (
    <group position={position} scale={scale}>
      <mesh castShadow position={[0, 2, 0]}>
        <cylinderGeometry args={[0.1, 0.2, 4, 6]} />
        <meshStandardMaterial color="#6f4e37" roughness={0.8} />
      </mesh>

      {[...Array(6)].map((_, i) => (
        <group
          key={i}
          rotation={[
            0.2,
            (Math.PI * 2 * i) / 6 + Math.random() * 0.5,
            Math.random() * 0.2 + 0.3
          ]}
          position={[0, 3.8, 0]}
        >
          <mesh castShadow>
            <coneGeometry args={[0.5, 2, 2]} />
            <meshStandardMaterial color="#2b9348" roughness={0.8} />
          </mesh>
        </group>
      ))}
    </group>
  );
};

const GameView = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const loadProduct = async () => {
      try {
        const { data } = await axios.get(`http://localhost:3000/api/v1/products/${id}`);
        if (!data.model3DUrl) {
          throw new Error('3D model not available for this product');
        }
        setProduct(data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };
    loadProduct();
  }, [id]);

  if (loading) {
    return <div className="fixed inset-0 bg-black flex items-center justify-center text-white">Loading...</div>;
  }

  if (error || !product?.model3DUrl) {
    return (
      <div className="fixed inset-0 bg-black flex items-center justify-center text-white">
        {error || '3D model not available'}
        <button
          onClick={() => navigate(-1)}
          className="mt-4 px-4 py-2 bg-red-600 rounded hover:bg-red-700"
        >
          Back to Product
        </button>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 bg-black">
      <button
        onClick={() => navigate(-1)}
        className="absolute top-4 left-4 z-50 px-4 py-2 bg-zinc-800 text-white rounded hover:bg-zinc-700"
      >
        Back to Product
      </button>

      <Canvas camera={{ position: [0, 2, 5], fov: 50 }}>
        <Suspense fallback={null}>
          <Stage environment="studio" intensity={0.5}>
            <Model url={product.model3DUrl} />
          </Stage>
          <OrbitControls 
            enablePan={true}
            enableZoom={true}
            enableRotate={true}
            minDistance={3}
            maxDistance={10}
          />
          <Environment preset="sunset" />
        </Suspense>
      </Canvas>
    </div>
  );
};

export default GameView;
